import type { ScenarioQuestion } from "./types";

type Diff = "beginner" | "intermediate" | "advanced";
type Fmt = "scenario" | "behavioral" | "situational" | "star";

interface QTemplate {
  group: string;
  sub: string;
  fmt: Fmt;
  diff: Diff;
  scenario: string;
  question: string;
  answer: string;
  feedback: string;
}

function buildQuestions(templates: QTemplate[], prefix: string): ScenarioQuestion[] {
  return templates.map((t, i) => ({
    id: `${prefix}-${i + 1}`,
    formatType: t.fmt,
    categoryGroup: t.group,
    subcategory: t.sub,
    scenarioPrompt: t.scenario,
    question: t.question,
    exampleAnswer: t.answer,
    feedback: t.feedback,
    difficulty: t.diff,
  }));
}

const ipBehavioralTemplates: QTemplate[] = [
  { group: "interview_preparation", sub: "behavioral", fmt: "behavioral", diff: "beginner", scenario: "A coworker thanks you publicly for helping them during a tough shift.", question: "How do you respond to public recognition?", answer: "I would be gracious and share the credit with the team. I would use the moment to reinforce the importance of teamwork rather than taking sole credit. Public recognition is an opportunity to model humility and collaboration.", feedback: "Gracious response with team credit." },
  { group: "interview_preparation", sub: "behavioral", fmt: "behavioral", diff: "beginner", scenario: "You observe a fellow nursing student struggling with a clinical skill during your rotation.", question: "How would you help a struggling peer?", answer: "I would offer assistance privately and without judgment. I would share tips that helped me learn the skill and offer to practice together. Supporting peers builds a stronger profession and mirrors the collaborative nature of nursing.", feedback: "Supportive peer mentorship without condescension." },
  { group: "interview_preparation", sub: "behavioral", fmt: "behavioral", diff: "intermediate", scenario: "During a team project, one member is not contributing equally.", question: "How would you handle an unequal team contribution?", answer: "I would have a private conversation to understand if there are barriers preventing their participation. I would redistribute tasks if needed and set clear expectations. If the issue persisted, I would involve the team leader. Direct communication is more productive than resentment.", feedback: "Direct communication about team equity." },
  { group: "interview_preparation", sub: "behavioral", fmt: "behavioral", diff: "intermediate", scenario: "You are asked to float to a unit you have never worked on before.", question: "How do you prepare for a float assignment?", answer: "I would ask for a brief orientation to the unit layout, equipment, and emergency procedures. I would identify a resource nurse, request a manageable assignment, and ask specific questions about unit-specific protocols. Transparency about my unfamiliarity protects patient safety.", feedback: "Proactive orientation-seeking and transparency." },
  { group: "interview_preparation", sub: "behavioral", fmt: "behavioral", diff: "advanced", scenario: "You witness a senior leader making an inappropriate comment to a staff member.", question: "How would you respond to misconduct by leadership?", answer: "I would document the incident with specifics and report it through the appropriate channel—HR or the ethics hotline. Power dynamics make it harder to address, but leadership misconduct affects the entire team. I would support the staff member affected and follow up on the report.", feedback: "Courage to report regardless of hierarchy." },
  { group: "interview_preparation", sub: "behavioral", fmt: "behavioral", diff: "beginner", scenario: "A patient compliments your care and asks for your name to mention in a survey.", question: "How would you respond to patient survey recognition?", answer: "I would thank the patient warmly and encourage them to complete the survey, as patient feedback helps improve care for everyone. I would also recognize that the care they received is a team effort and encourage recognition of others who contributed.", feedback: "Welcoming feedback while crediting the team." },
  { group: "interview_preparation", sub: "behavioral", fmt: "behavioral", diff: "intermediate", scenario: "Your manager asks you to train on a piece of equipment during your day off.", question: "How would you respond to a training request on your off day?", answer: "I would assess whether the training is mandatory or optional and discuss fair compensation or schedule accommodation. I value professional development but also need to maintain work-life balance. I would propose alternative training times that work within my schedule.", feedback: "Professional boundary-setting while showing commitment to learning." },
  { group: "interview_preparation", sub: "behavioral", fmt: "behavioral", diff: "beginner", scenario: "You are nervous about your first job interview and want to make a strong impression.", question: "How do you prepare for a nursing interview?", answer: "I research the facility thoroughly, practice common interview questions with STAR-format answers, prepare questions to ask, select professional attire, and arrive early. I review my clinical experiences for relevant examples and prepare to discuss my strengths and growth areas honestly.", feedback: "Thorough preparation demonstrates professionalism." },
  { group: "interview_preparation", sub: "behavioral", fmt: "behavioral", diff: "advanced", scenario: "You are in a second interview and they ask about your experience with diversity and inclusion.", question: "How do you promote diversity and inclusion in your practice?", answer: "I commit to providing culturally sensitive care by learning about different cultural health practices, using professional interpreters, respecting dietary and religious preferences, and examining my own implicit biases. I advocate for equitable treatment and speak up when I observe discrimination. I seek out education on health disparities.", feedback: "Active DEI engagement beyond surface-level awareness." },
  { group: "interview_preparation", sub: "behavioral", fmt: "behavioral", diff: "intermediate", scenario: "An interviewer asks you about a weakness, and you do not want to seem incompetent.", question: "How would you discuss a genuine weakness authentically?", answer: "I would choose a real area for growth that I am actively working on—not a disguised strength. For example: 'I tend to be very thorough in my documentation, which sometimes takes longer than my peers. I have been working on streamlining my charting process while maintaining accuracy.' The key is showing self-awareness and active improvement.", feedback: "Authentic self-disclosure with demonstrated improvement efforts." },
  { group: "interview_preparation", sub: "behavioral", fmt: "behavioral", diff: "beginner", scenario: "You are asked about your biggest accomplishment outside of nursing.", question: "How would you relate a non-nursing accomplishment to your nursing career?", answer: "I would share a meaningful accomplishment and connect it to nursing qualities: 'I completed a marathon after training for a year. The discipline, resilience, and commitment required parallel what I bring to nursing—perseverance through challenges, consistent preparation, and the ability to push through difficult moments while maintaining focus on the goal.'", feedback: "Connecting personal qualities to professional nursing attributes." },
  { group: "interview_preparation", sub: "behavioral", fmt: "behavioral", diff: "intermediate", scenario: "During the interview, you realize you misunderstood a question and gave an irrelevant answer.", question: "How would you recover from misunderstanding an interview question?", answer: "I would simply say, 'I think I may have misunderstood your question. Could you rephrase it so I can give you a more relevant answer?' Honest self-correction shows self-awareness and integrity. Interviewers appreciate candidates who listen carefully and want to provide the most accurate response.", feedback: "Self-correction demonstrates self-awareness and honesty." },
];

const ipClinicalTemplates: QTemplate[] = [
  { group: "interview_preparation", sub: "clinical_judgment", fmt: "scenario", diff: "beginner", scenario: "A patient complains of a headache after a lumbar puncture.", question: "What post-LP complication is this and how would you manage it?", answer: "A post-LP headache (spinal headache) occurs from CSF leak. It is typically worse when sitting or standing and improves when lying down. I would keep the patient flat, encourage fluids and caffeine, administer analgesics, and notify the provider if symptoms are severe. A blood patch may be needed for persistent cases.", feedback: "Recognition and management of post-LP headache." },
  { group: "interview_preparation", sub: "clinical_judgment", fmt: "scenario", diff: "intermediate", scenario: "A patient with a history of falls is prescribed a new sedating medication.", question: "What safety considerations would you implement?", answer: "I would review the patient's fall risk assessment and update it given the new sedating medication. I would implement fall precautions: bed alarm, non-slip footwear, bed in lowest position, call light within reach. I would educate the patient about the sedating effects and ensure someone assists with ambulation. I would notify the provider if I believe the fall risk outweighs the medication benefit.", feedback: "Anticipating medication-related fall risk and implementing proactive measures." },
  { group: "interview_preparation", sub: "clinical_judgment", fmt: "scenario", diff: "advanced", scenario: "A patient with Addison's disease presents with hypotension, weakness, and darkened skin pigmentation.", question: "What crisis might this patient be experiencing?", answer: "These symptoms suggest an Addisonian crisis—acute adrenal insufficiency. This is a medical emergency. I would administer IV hydrocortisone (stress dose steroids) per protocol, begin aggressive IV fluid resuscitation with normal saline, monitor blood glucose for hypoglycemia, obtain cortisol levels, and provide continuous hemodynamic monitoring. I would identify and treat the precipitating stressor.", feedback: "Recognition of adrenal crisis and emergent steroid replacement." },
  { group: "interview_preparation", sub: "clinical_judgment", fmt: "scenario", diff: "intermediate", scenario: "A patient receiving tube feeding develops abdominal distension and a residual volume of 350 mL.", question: "How would you manage high gastric residuals during tube feeding?", answer: "I would hold the tube feeding per protocol (typically when residual exceeds 250-500 mL depending on facility policy). I would return the aspirated contents to the stomach, elevate the head of bed to 30-45 degrees, and reassess in 1-2 hours. I would notify the provider about the high residual and assess for signs of intolerance: nausea, vomiting, distension. I would anticipate a possible rate reduction or prokinetic agent order.", feedback: "Systematic management of feeding intolerance with provider notification." },
  { group: "interview_preparation", sub: "clinical_judgment", fmt: "scenario", diff: "beginner", scenario: "A patient with a Foley catheter develops cloudy, foul-smelling urine.", question: "What does this urinalysis change suggest?", answer: "Cloudy, foul-smelling urine in a catheterized patient suggests a catheter-associated urinary tract infection (CAUTI). I would assess for other UTI symptoms: fever, suprapubic pain, confusion in elderly patients. I would obtain a urine sample for urinalysis and culture before antibiotics are started. I would assess whether the catheter is still medically necessary—prompt removal reduces infection risk.", feedback: "CAUTI recognition with emphasis on catheter necessity assessment." },
  { group: "interview_preparation", sub: "clinical_judgment", fmt: "scenario", diff: "advanced", scenario: "A post-craniotomy patient develops clear fluid draining from their nose.", question: "What does clear nasal drainage after brain surgery suggest?", answer: "Clear nasal drainage after craniotomy could indicate a CSF leak, which is a serious complication. I would test the fluid for glucose (CSF contains glucose while nasal mucus does not) or look for the halo sign on a gauze pad. I would not suction the nose or pack the nares. I would keep the head of bed elevated, notify the neurosurgeon immediately, and monitor for signs of meningitis.", feedback: "CSF leak recognition with contraindicated interventions identified." },
  { group: "interview_preparation", sub: "clinical_judgment", fmt: "scenario", diff: "intermediate", scenario: "A patient with a history of thyroid disease develops puffiness around the eyes, weight gain, and fatigue.", question: "What thyroid condition do these symptoms suggest?", answer: "These symptoms—periorbital edema, weight gain, and fatigue—suggest hypothyroidism (myxedema). I would assess for additional symptoms: constipation, cold intolerance, bradycardia, dry skin. I would check the patient's TSH and T4 levels, review their thyroid medication compliance, and notify the provider. Severe hypothyroidism can progress to myxedema coma, which is life-threatening.", feedback: "Hypothyroidism recognition with awareness of severe complications." },
  { group: "interview_preparation", sub: "clinical_judgment", fmt: "scenario", diff: "advanced", scenario: "A burn patient develops eschar on their extremity with decreased pulses distally.", question: "What complication is developing and what is the intervention?", answer: "Circumferential eschar with decreased distal pulses indicates compartment syndrome from the tight, inelastic burned tissue restricting blood flow. This is a surgical emergency requiring escharotomy—surgical incision through the eschar to release pressure. I would assess for the 5 Ps (pain, pallor, pulselessness, paresthesia, paralysis), elevate the extremity, and notify the burn surgeon immediately.", feedback: "Recognition of eschar-related compartment syndrome requiring surgical intervention." },
  { group: "interview_preparation", sub: "clinical_judgment", fmt: "scenario", diff: "beginner", scenario: "A patient reports their knee feels hot and swollen after a joint injection.", question: "How would you assess a swollen joint after injection?", answer: "I would assess the joint for signs of infection versus inflammation: check temperature (local and systemic), assess for redness, swelling, and range of motion. Some swelling after injection is expected, but fever, increasing redness, and purulent drainage would suggest septic arthritis—a medical emergency. I would notify the provider, especially if fever develops, and anticipate joint aspiration and cultures.", feedback: "Distinguishing expected post-injection inflammation from septic arthritis." },
  { group: "interview_preparation", sub: "clinical_judgment", fmt: "scenario", diff: "intermediate", scenario: "A patient on lithium for bipolar disorder reports excessive thirst, frequent urination, and tremors.", question: "What do these symptoms suggest in a lithium patient?", answer: "Excessive thirst, polyuria, and tremors in a patient on lithium may indicate lithium toxicity or lithium-induced nephrogenic diabetes insipidus. I would obtain a stat lithium level, check renal function (BUN, creatinine), assess electrolytes and thyroid function, and monitor intake and output. I would notify the provider and ensure the patient maintains adequate hydration while awaiting results.", feedback: "Recognition of lithium toxicity symptoms with appropriate lab workup." },
  { group: "interview_preparation", sub: "clinical_judgment", fmt: "scenario", diff: "advanced", scenario: "A patient receiving a platelet transfusion develops rigors, hypotension, and a high fever.", question: "What transfusion reaction do you suspect?", answer: "Severe rigors, hypotension, and high fever during a platelet transfusion suggest a bacterial contamination of the blood product—a septic transfusion reaction. This is a medical emergency. I would immediately stop the transfusion, maintain IV access with normal saline, draw blood cultures from the patient and send the platelet bag for culture, administer broad-spectrum antibiotics, and provide hemodynamic support. This has a high mortality rate.", feedback: "Recognition of septic transfusion reaction as distinct from other reactions." },
  { group: "interview_preparation", sub: "clinical_judgment", fmt: "scenario", diff: "beginner", scenario: "A patient with a cast on their arm complains that their fingers are turning blue and they cannot feel them.", question: "What does this indicate and what should you do?", answer: "Blue fingers with numbness in a casted extremity indicate neurovascular compromise—likely compartment syndrome from swelling within the cast. This is urgent. I would perform a neurovascular check (circulation, sensation, movement), elevate the extremity, notify the provider immediately, and prepare for cast bivalving or removal. Do not wait to see if it improves—nerve damage can occur within hours.", feedback: "Urgent neurovascular compromise recognition in orthopedic patients." },
];

const ipScenarioTemplates: QTemplate[] = [
  { group: "interview_preparation", sub: "scenario_responses", fmt: "scenario", diff: "beginner", scenario: "A visitor brings flowers to a patient who is immunocompromised.", question: "How would you handle flowers in an immunocompromised patient's room?", answer: "I would gently explain that fresh flowers and plants can harbor bacteria and fungi that pose a risk to immunocompromised patients. I would suggest alternatives like silk flowers or cards. I would not make the visitor feel bad but would explain the medical reasoning clearly. I would relocate the flowers to a safe area.", feedback: "Infection control education delivered with sensitivity." },
  { group: "interview_preparation", sub: "scenario_responses", fmt: "scenario", diff: "intermediate", scenario: "A patient asks you to administer a medication that a family member brought from home.", question: "How would you handle a request to administer outside medications?", answer: "I would explain that I cannot administer medications that have not been verified and ordered through our pharmacy. The medication would need to be identified, verified by our pharmacist, and ordered by the physician before administration. I would document the patient's home medications during medication reconciliation and work with the team to ensure they receive their necessary medications through proper channels.", feedback: "Proper medication verification through hospital pharmacy systems." },
  { group: "interview_preparation", sub: "scenario_responses", fmt: "scenario", diff: "advanced", scenario: "A patient in the ER is brought in unconscious with no identification.", question: "How would you provide care to an unidentified patient?", answer: "I would follow the facility's John/Jane Doe protocol: assign a temporary identification, provide all necessary emergency treatment, attempt to identify the patient through personal effects or law enforcement, and ensure proper documentation under the temporary ID. I would not delay life-saving treatment for identification. Once identified, all records would be merged.", feedback: "Emergency care provision regardless of identification status." },
  { group: "interview_preparation", sub: "scenario_responses", fmt: "scenario", diff: "beginner", scenario: "A patient asks you to change their physician because they do not trust them.", question: "How would you handle a request to change physicians?", answer: "I would listen to the patient's concerns and validate their feelings. I would explain the process for requesting a physician change through patient relations or the charge nurse. If the concern involves safety issues, I would report them through proper channels. Patients have the right to choose their care providers when feasible.", feedback: "Supporting patient rights in provider selection." },
  { group: "interview_preparation", sub: "scenario_responses", fmt: "scenario", diff: "intermediate", scenario: "A patient repeatedly refuses nursing assessments but wants to stay in the hospital.", question: "How would you handle a patient who refuses assessment?", answer: "I would explore the reason for refusal—pain, modesty, previous negative experience, or fear. I would explain why the assessment is important for their safety and treatment. I would offer accommodations like same-gender assessment or modified approaches. I would document each refusal and the education provided. I would notify the provider that assessments are being refused.", feedback: "Understanding refusal reasons and documenting appropriately." },
  { group: "interview_preparation", sub: "scenario_responses", fmt: "scenario", diff: "intermediate", scenario: "A patient asks you to turn off the camera in their room used for monitoring.", question: "How would you handle a privacy concern about monitoring cameras?", answer: "I would acknowledge the patient's privacy concern and explain the purpose of the monitoring—whether it is for fall prevention, safety monitoring, or clinical observation. I would check with the charge nurse about whether the monitoring is medically ordered or discretionary. If it is ordered, I would explain the medical necessity. I would ensure the camera is only used as intended and follow facility policy.", feedback: "Balancing privacy with safety monitoring needs." },
  { group: "interview_preparation", sub: "scenario_responses", fmt: "scenario", diff: "beginner", scenario: "A patient on bed rest asks you to help them walk to the window to see outside.", question: "How would you handle a bed rest violation request?", answer: "I would empathize with their desire to see outside but explain that bed rest is ordered for a specific medical reason. I would explore alternatives: repositioning the bed toward the window, bringing photos or videos of outside, or using a tablet for virtual scenery. I would discuss with the provider whether brief sitting in a chair might be possible.", feedback: "Empathetic alternatives while maintaining medical orders." },
  { group: "interview_preparation", sub: "scenario_responses", fmt: "scenario", diff: "advanced", scenario: "A patient with a Do Not Resuscitate order goes into cardiac arrest with a new nurse who is unsure about the order.", question: "How would you ensure DNR compliance during a crisis?", answer: "I would immediately verify the DNR order in the chart. If confirmed, I would direct the team to provide comfort measures only—no CPR, no intubation, no defibrillation. I would calmly but firmly communicate the DNR status: 'This patient has a valid DNR order. We will provide comfort care only.' I would support the family and ensure the attending is notified. I would debrief with the new nurse afterward.", feedback: "Clear, authoritative communication of DNR status during emergencies." },
];

const ipStarTemplates: QTemplate[] = [
  { group: "interview_preparation", sub: "star_examples", fmt: "star", diff: "beginner", scenario: "Tell me about a time you demonstrated attention to detail.", question: "When has your attention to detail prevented a problem?", answer: "While scanning medications for a patient, I noticed the barcode did not match the prescribed medication. I stopped, rechecked the order, and discovered the pharmacy had dispensed the wrong medication—a similar-sounding drug. By following proper medication scanning protocol, I prevented a potentially harmful medication error. This reinforced the importance of technology-assisted safety checks.", feedback: "Technology as a safety tool with human verification." },
  { group: "interview_preparation", sub: "star_examples", fmt: "star", diff: "intermediate", scenario: "Describe a situation where you had to think on your feet.", question: "When have you had to adapt quickly to an unexpected clinical situation?", answer: "A patient's peripheral IV infiltrated during a critical antibiotic infusion, and I could not obtain peripheral access due to difficult venous access. I notified the provider, advocated for a PICC line placement, and in the meantime, obtained an order for the oral equivalent of the antibiotic to avoid missing a dose. This ensured continuity of treatment while a long-term access solution was arranged.", feedback: "Creative problem-solving for vascular access challenges." },
  { group: "interview_preparation", sub: "star_examples", fmt: "star", diff: "advanced", scenario: "Tell me about leading a quality improvement initiative.", question: "Describe a quality improvement project you contributed to.", answer: "I led a project to reduce CAUTI rates on our unit. I analyzed our catheter utilization data, identified patients with catheters past the recommended duration, implemented daily catheter necessity assessments, and created an algorithm for early removal criteria. Over three months, our CAUTI rate decreased by 40% and unnecessary catheter days were reduced by 60%.", feedback: "Data-driven quality improvement with measurable outcomes." },
  { group: "interview_preparation", sub: "star_examples", fmt: "star", diff: "beginner", scenario: "Tell me about receiving feedback that changed your practice.", question: "How has feedback improved your nursing practice?", answer: "My preceptor observed that I was charting assessments in a way that was accurate but hard for other nurses to follow quickly. She showed me how to organize notes by system and highlight changes from the baseline. I adopted her method, and subsequent nurses told me my charts were easy to follow. I learned that documentation is communication—it needs to be useful to the reader.", feedback: "Incorporating feedback into practice improvement." },
  { group: "interview_preparation", sub: "star_examples", fmt: "star", diff: "intermediate", scenario: "Describe teaching a skill to someone else.", question: "When have you taught a clinical skill to a peer?", answer: "A fellow nursing student was struggling with sterile gloving technique. I broke it down into specific steps, demonstrated slowly, had her practice on a sterile tray multiple times, and gave her feedback on each attempt. By the end of the session, she could glove up consistently. The experience taught me that breaking complex skills into simple steps makes them accessible.", feedback: "Breaking skills into learnable components for effective teaching." },
];

const ipCommonTemplates: QTemplate[] = [
  { group: "interview_preparation", sub: "common_nursing_interview", fmt: "behavioral", diff: "beginner", scenario: "The interviewer asks: 'What is your philosophy of nursing?'", question: "What is your nursing philosophy?", answer: "My nursing philosophy centers on treating every patient as a whole person—body, mind, and spirit. I believe in evidence-based practice guided by compassion, patient autonomy, and advocacy. I see nursing as both a science and an art: the science of clinical knowledge and the art of human connection. I am committed to lifelong learning and to treating every patient with dignity regardless of their circumstances.", feedback: "A clear, authentic philosophy that balances science and compassion." },
  { group: "interview_preparation", sub: "common_nursing_interview", fmt: "behavioral", diff: "beginner", scenario: "The interviewer asks: 'Tell me about yourself.'", question: "How would you introduce yourself in an interview?", answer: "I am a recently graduated registered nurse with a strong foundation in medical-surgical nursing from my clinical rotations. During school, I maintained a high GPA while working as a patient care technician, which gave me real-world healthcare experience. I chose nursing because I wanted a career that combines scientific thinking with human connection. I am eager to bring my clinical knowledge and passion for patient care to your team.", feedback: "Concise professional introduction with relevant highlights." },
  { group: "interview_preparation", sub: "common_nursing_interview", fmt: "behavioral", diff: "intermediate", scenario: "The interviewer asks: 'How do you handle ethical dilemmas?'", question: "What is your approach to ethical decision-making?", answer: "I use an ethical framework that starts with identifying the core issue, considering all stakeholders, reviewing relevant policies and laws, and consulting with colleagues and ethics resources. I consider principles of autonomy, beneficence, non-maleficence, and justice. I have found that most ethical dilemmas are not clear-cut, and the best approach involves careful deliberation and team input.", feedback: "Structured ethical decision-making framework." },
  { group: "interview_preparation", sub: "common_nursing_interview", fmt: "behavioral", diff: "beginner", scenario: "The interviewer asks: 'Are you comfortable working night shifts?'", question: "How do you feel about working night shifts?", answer: "I understand that night shifts are part of nursing, especially for new graduates. I am prepared to work nights and have already developed strategies for adapting my sleep schedule, maintaining good nutrition, and staying alert. I know that night shift nurses play a crucial role in patient care continuity, and I am committed to providing excellent care regardless of the shift.", feedback: "Willingness with preparation strategies for shift adaptation." },
  { group: "interview_preparation", sub: "common_nursing_interview", fmt: "behavioral", diff: "intermediate", scenario: "The interviewer asks: 'How do you handle conflict with a coworker?'", question: "Describe your approach to workplace conflict.", answer: "I address conflict directly and privately with the person involved. I focus on the issue, not the personality. I use I-statements to express my perspective: 'I felt concerned when...' rather than accusatory language. I actively listen to their viewpoint and work toward a mutual solution. If we cannot resolve it together, I involve a supervisor. I believe most conflicts arise from miscommunication that can be clarified.", feedback: "Direct, professional conflict resolution approach." },
];

const ipDifficultTemplates: QTemplate[] = [
  { group: "interview_preparation", sub: "difficult_interviewer", fmt: "scenario", diff: "advanced", scenario: "The interviewer challenges you: 'New graduates are a liability. Change my mind.'", question: "How would you respond to a hostile stance against new graduates?", answer: "I would respond with confidence: 'I understand that hiring new graduates involves an investment. However, new graduates bring current evidence-based knowledge, eagerness to learn, and fresh perspectives. Studies show that facilities with strong new graduate programs have better long-term retention. I am committed to this unit and will work hard to become an asset quickly. My clinical evaluations demonstrate strong critical thinking and a willingness to learn.'", feedback: "Confident rebuttal with supporting evidence." },
  { group: "interview_preparation", sub: "difficult_interviewer", fmt: "scenario", diff: "advanced", scenario: "The interviewer says: 'I do not see anything on your resume that makes you stand out.'", question: "How would you respond to having your qualifications minimized?", answer: "I would maintain composure and offer additional context: 'I appreciate your candor. Let me share what the resume might not fully convey. During my clinical rotations, I consistently received the highest evaluation marks for clinical judgment. I initiated a patient safety project that was adopted by the unit. And my patient care tech experience gave me hands-on skills that many new graduates lack. I would love the opportunity to demonstrate my abilities.'", feedback: "Adding context to paper qualifications with concrete examples." },
  { group: "interview_preparation", sub: "difficult_interviewer", fmt: "scenario", diff: "intermediate", scenario: "The interviewer asks: 'What would you do if you hated working here?'", question: "How would you handle an unexpected provocative question?", answer: "I would give an honest, mature response: 'I have done thorough research on this unit and I am confident it is a good fit. However, if I found the work environment was not meeting my professional needs, I would first try to identify what was not working and address it through appropriate channels. I would give it a fair chance before making any decisions, and I would always maintain my professional standards regardless.'", feedback: "Mature response to a provocative question." },
  { group: "interview_preparation", sub: "difficult_interviewer", fmt: "scenario", diff: "advanced", scenario: "The interviewer gives you a clinical scenario and then tells you your answer was wrong.", question: "How would you handle being told your interview answer was incorrect?", answer: "I would remain calm and open: 'Thank you for the correction. Can you help me understand the rationale? I want to learn the right approach.' I would not become defensive or argumentative. If I believe my answer was actually correct, I might say, 'I have seen it done this way based on these guidelines—could there be more than one acceptable approach?' Humility combined with clinical curiosity is more impressive than defensiveness.", feedback: "Learning orientation even when challenged." },
];

const ipPanelTemplates: QTemplate[] = [
  { group: "interview_preparation", sub: "panel_interview", fmt: "scenario", diff: "intermediate", scenario: "During a panel interview, a staff nurse asks about your clinical strengths and weaknesses.", question: "How would you discuss strengths and weaknesses with a staff nurse interviewer?", answer: "I would be specific and clinically relevant: 'My strengths include thorough patient assessment, strong IV skills, and effective patient education. My areas for growth include building speed in my medication administration workflow and gaining more experience with complex wound care. I am actively working on both through practice and mentorship.' A staff nurse appreciates clinical specifics over vague generalities.", feedback: "Clinically specific self-assessment for a peer audience." },
  { group: "interview_preparation", sub: "panel_interview", fmt: "scenario", diff: "beginner", scenario: "The HR representative on the panel asks about your availability and commitment.", question: "How would you address commitment questions from HR?", answer: "I would express genuine commitment: 'I am looking for a long-term professional home, not just a first job. I am committed to this unit's orientation program and plan to be here for at least two to three years to build a strong foundation. I am excited about the growth opportunities I have heard about here.' This addresses HR's concern about turnover costs.", feedback: "Addressing retention concerns with specific commitment language." },
  { group: "interview_preparation", sub: "panel_interview", fmt: "scenario", diff: "advanced", scenario: "Panel members ask you to role-play a difficult conversation with a family member.", question: "How would you handle a role-play scenario in a panel interview?", answer: "I would take a moment to collect my thoughts, then engage fully in the scenario. I would use therapeutic communication techniques: active listening, empathy, clear explanations, and setting expectations. I would treat the role-play as a real interaction rather than a performance. Afterward, I would be open to feedback on my approach.", feedback: "Full engagement in role-play with therapeutic communication skills." },
];

const wsTemplates: QTemplate[] = [
  { group: "workplace_scenarios", sub: "prioritization", fmt: "scenario", diff: "beginner", scenario: "You are starting your shift and all five patients need assessments within the first hour.", question: "How would you organize your initial assessment rounds?", answer: "I would quickly review the census sheet for high-acuity patients and start with the most critical—post-operative, hemodynamically unstable, or newly admitted patients. I would do focused assessments first, noting concerns, then return for more thorough assessments. I would delegate vital signs to the CNA to save time. A quick round on all patients is better than a thorough assessment on one while others are unseen.", feedback: "Broad initial assessment before deep dives." },
  { group: "workplace_scenarios", sub: "prioritization", fmt: "scenario", diff: "intermediate", scenario: "Your patient needs to go to dialysis but also has a pending antibiotic due.", question: "How would you coordinate dialysis with medication timing?", answer: "I would check whether the antibiotic is dialyzable—if it is removed by dialysis, it should ideally be given after treatment. I would consult with the pharmacist about optimal timing and communicate with the dialysis team about the schedule. I would document the coordination and ensure the patient receives both treatments appropriately.", feedback: "Coordination of dialysis timing with medication scheduling." },
  { group: "workplace_scenarios", sub: "prioritization", fmt: "scenario", diff: "advanced", scenario: "Two of your patients are actively deteriorating and you are alone.", question: "How would you manage two deteriorating patients simultaneously?", answer: "I would immediately call for help—this is not a situation to manage alone. I would quickly triage which patient is more immediately life-threatening and go to them first while directing anyone who responds to the second patient. I would activate the rapid response team if needed. I would delegate clearly: 'You take room 3, here is the situation.' I would document the timeline and my decision-making rationale.", feedback: "Calling for help and rapid triage between competing emergencies." },
  { group: "workplace_scenarios", sub: "delegation", fmt: "scenario", diff: "beginner", scenario: "You need help turning a patient but no one is immediately available.", question: "How would you get help for a task requiring two people?", answer: "I would use the call bell to request help from the nurses' station. I would check neighboring rooms for available staff. I would ask the CNA, another nurse, or even the unit clerk to assist briefly. I would never attempt to turn a patient alone if their condition requires two-person assistance. I would plan to coordinate turning schedules with available staff for the rest of the shift.", feedback: "Never compromise safety by attempting two-person tasks alone." },
  { group: "workplace_scenarios", sub: "delegation", fmt: "scenario", diff: "intermediate", scenario: "You are the charge nurse and one CNA is refusing to take vital signs on a combative patient.", question: "How would you handle a CNA refusing a delegated task?", answer: "I would first assess the safety concern—if the patient is genuinely combative, the CNA's safety needs to be addressed. I would offer to accompany the CNA, provide de-escalation strategies, or reassign the task to a more experienced team member. If the refusal is without safety justification, I would address it as a performance issue. I would document the interaction and ensure patient care is completed.", feedback: "Assess safety concerns before addressing refusal as a performance issue." },
  { group: "workplace_scenarios", sub: "patient_safety", fmt: "scenario", diff: "beginner", scenario: "A patient in contact isolation needs to be transported to radiology.", question: "What infection control precautions would you implement during transport?", answer: "I would ensure the patient wears a clean gown and the affected area is covered. I would clean the transport equipment before and after use. I would notify the receiving department about the isolation status so they can prepare. I would ensure the transport team uses appropriate PPE. I would document the transport and infection precautions taken.", feedback: "Infection control continuity during patient transport." },
  { group: "workplace_scenarios", sub: "patient_safety", fmt: "scenario", diff: "intermediate", scenario: "You discover that the crash cart on your unit has not been checked in 48 hours.", question: "How would you address an unchecked crash cart?", answer: "I would check the crash cart immediately—verify that defibrillator is functional, medications are within expiration dates, supplies are stocked, and the cart is properly sealed. I would report the lapse to the charge nurse and the unit manager. I would review who was responsible for the check and ensure the daily verification process is reinforced. An unchecked crash cart during a code could cost a life.", feedback: "Immediate correction of equipment safety lapses." },
  { group: "workplace_scenarios", sub: "medication_error", fmt: "scenario", diff: "beginner", scenario: "A patient asks you why they are getting a new pill they have never seen before.", question: "How would you handle a patient noticing a medication change?", answer: "I would thank the patient for their vigilance and verify the medication against the current order. I would explain any new medications, why they were ordered, expected effects, and side effects to watch for. If I cannot verify the new medication, I would hold it until I can confirm it with the pharmacist or provider. Patient awareness is a crucial safety layer.", feedback: "Patient medication awareness as a safety check." },
  { group: "workplace_scenarios", sub: "handoff_communication", fmt: "scenario", diff: "intermediate", scenario: "You are transitioning from paper brain sheets to an electronic handoff tool.", question: "How would you adapt to a new handoff system?", answer: "I would attend training sessions and practice with the new tool before using it in real handoffs. I would keep my paper brain sheet as a backup during the transition period. I would provide feedback to the implementation team about any gaps or concerns. I would focus on the content of the handoff—the method is less important than ensuring all critical information is transferred.", feedback: "Smooth technology transitions with content focus." },
  { group: "workplace_scenarios", sub: "difficult_coworkers", fmt: "scenario", diff: "advanced", scenario: "A colleague spreads rumors that you are having a relationship with a physician.", question: "How would you address a false personal rumor in the workplace?", answer: "I would address this directly and seriously. I would speak privately with the person spreading the rumor: 'I am aware of a rumor circulating about me that is completely false and damaging to my professional reputation. I need it to stop immediately.' If it continued, I would document the harassment and report it to HR. False rumors about personal relationships can constitute workplace harassment.", feedback: "Direct confrontation and HR escalation for harmful rumors." },
  { group: "workplace_scenarios", sub: "interdisciplinary_communication", fmt: "scenario", diff: "beginner", scenario: "You need to call a physician who you know has a reputation for being difficult on the phone.", question: "How would you prepare for a call with a difficult physician?", answer: "I would prepare thoroughly before calling: have all relevant data organized using SBAR, anticipate questions the physician might ask, and have the chart open. I would be confident, concise, and professional. I would not apologize for calling—I am advocating for my patient. I would document the call regardless of how it goes. Preparation is the best antidote to a difficult interaction.", feedback: "Thorough preparation reduces vulnerability to difficult interactions." },
];

const ctTemplates: QTemplate[] = [
  { group: "clinical_transition", sub: "first_shift", fmt: "scenario", diff: "beginner", scenario: "You finish giving report and realize you forgot to mention an important detail about a patient.", question: "How would you handle remembering missed information after report?", answer: "I would immediately contact the oncoming nurse—whether by phone, text, or going back to the unit. I would not assume they will discover the information on their own. I would say, 'I apologize for missing this during report—I wanted to make sure you know that...' Timely correction of missed information is professional, not embarrassing.", feedback: "Immediate correction of missed handoff information." },
  { group: "clinical_transition", sub: "first_shift", fmt: "scenario", diff: "beginner", scenario: "You cannot figure out how to use the IV pump during your orientation.", question: "How would you handle equipment you do not know how to use?", answer: "I would ask my preceptor or a colleague to show me how to operate the pump. I would not attempt to use equipment I am unfamiliar with independently. I would take notes and practice programming the pump during downtime. Many hospitals have online training modules and simulation equipment for practice. There is no shame in needing to learn new equipment.", feedback: "Asking for help with unfamiliar equipment is expected and safe." },
  { group: "clinical_transition", sub: "new_nurse_anxiety", fmt: "scenario", diff: "intermediate", scenario: "You are dreading a specific type of patient interaction (wound care, death, psychiatric patients).", question: "How would you address avoidance of challenging clinical situations?", answer: "I would identify the specific source of my discomfort—is it lack of knowledge, fear of making a mistake, or personal emotional triggers? I would seek out supervised exposure to build competence and confidence. I would discuss my concerns with my preceptor and develop a plan for gradual exposure. Avoiding clinical situations is not sustainable and limits professional growth.", feedback: "Identifying root causes of clinical avoidance and gradual exposure." },
  { group: "clinical_transition", sub: "time_management", fmt: "scenario", diff: "intermediate", scenario: "Your shift is very quiet and you have completed all immediate tasks.", question: "How would you use downtime productively during a quiet shift?", answer: "I would use the time to catch up on documentation, review my patients' charts thoroughly, prepare for upcoming procedures or discharges, complete required education modules, organize supply rooms, and review policies or medications I want to learn about. I would also check in on neighboring patients if my colleagues are busy. Quiet time is an opportunity, not an excuse for complacency.", feedback: "Productive use of downtime for professional development." },
  { group: "clinical_transition", sub: "documentation_challenges", fmt: "scenario", diff: "beginner", scenario: "You are not sure if an assessment finding is normal or abnormal.", question: "How would you document a finding you are unsure about?", answer: "I would document exactly what I observed using objective, descriptive language without making a diagnosis. For example, 'Area of redness 3cm x 2cm on left heel, non-blanchable, skin intact' rather than 'Stage 1 pressure injury' if I am unsure of staging. I would compare to previous assessments, ask my preceptor, and consult with a specialist if needed. Accurate description allows others to assess the finding.", feedback: "Objective description when clinical interpretation is uncertain." },
  { group: "clinical_transition", sub: "critical_thinking_drills", fmt: "scenario", diff: "intermediate", scenario: "A patient's procalcitonin level is elevated at 5.2 ng/mL.", question: "What does an elevated procalcitonin suggest?", answer: "Procalcitonin is a biomarker that rises in bacterial infections and sepsis. A level of 5.2 is significantly elevated and suggests a serious bacterial infection. Combined with clinical signs, this supports initiating or continuing antibiotics. Procalcitonin can also guide antibiotic stewardship—declining levels support consideration of stopping antibiotics. I would assess for infection sources and notify the provider.", feedback: "Using procalcitonin for infection assessment and antibiotic stewardship." },
  { group: "clinical_transition", sub: "critical_thinking_drills", fmt: "scenario", diff: "advanced", scenario: "A patient's D-dimer is elevated at 1,200 ng/mL but they have no symptoms of DVT or PE.", question: "How would you interpret an elevated D-dimer without typical symptoms?", answer: "D-dimer is a sensitive but not specific test—it is elevated in many conditions beyond VTE: post-surgery, infection, inflammation, pregnancy, cancer, and advanced age. An elevated D-dimer with low clinical probability may not require further workup. I would assess the clinical context, use a validated clinical scoring tool like the Wells criteria, and discuss with the provider whether imaging is warranted.", feedback: "Understanding D-dimer limitations and clinical probability assessment." },
  { group: "clinical_transition", sub: "critical_thinking_drills", fmt: "scenario", diff: "beginner", scenario: "A patient's blood glucose is 78 mg/dL and they are scheduled for insulin.", question: "Should you administer the scheduled insulin?", answer: "A blood glucose of 78 is normal but on the lower end. Before giving insulin, I would assess what type of insulin is ordered—basal (long-acting) insulin may still be given per protocol, but mealtime (rapid-acting) insulin should be held if the patient is not eating or has a low glucose. I would check if the patient is about to eat and follow the facility's insulin administration guidelines. When in doubt, I would hold and notify the provider.", feedback: "Contextual insulin decision-making based on type and clinical situation." },
];

const pdTemplates: QTemplate[] = [
  { group: "professional_development", sub: "professional_boundaries", fmt: "scenario", diff: "intermediate", scenario: "A patient asks for your personal cell phone number to reach you directly.", question: "How would you decline sharing personal contact information?", answer: "I would decline warmly: 'I appreciate your trust in me, but I need to keep my personal and professional contact separate. If you need to reach the nursing staff, please call the unit directly and anyone on the team can help you.' I would ensure they have the unit phone number and understand how to reach their care team.", feedback: "Professional decline with alternative contact information." },
  { group: "professional_development", sub: "ethical_dilemmas", fmt: "scenario", diff: "advanced", scenario: "You discover that a patient has been misdiagnosed and the error has led to unnecessary treatment.", question: "How would you handle discovering a possible misdiagnosis?", answer: "I would not make a diagnosis or challenge the physician directly about a diagnosis outside my scope. However, I would present my clinical findings that may not align with the current diagnosis: 'I have noticed some findings that do not seem consistent with the current diagnosis—would it be worth considering additional workup?' I would document my findings and advocacy. Patient safety may require diplomatic persistence.", feedback: "Diplomatic advocacy for diagnostic reconsideration within scope." },
  { group: "professional_development", sub: "workplace_bullying", fmt: "scenario", diff: "intermediate", scenario: "A nurse deliberately gives you wrong information about a patient as a 'test.'", question: "How would you handle being deliberately misinformed by a colleague?", answer: "I would always verify critical patient information independently through chart review rather than relying solely on verbal information. If I discovered I was deliberately given wrong information, I would address it directly: 'I found that the information you gave me was incorrect, and this could have affected patient safety. I need to be able to trust the information my colleagues give me.' I would report the incident to my manager.", feedback: "Independent verification and zero tolerance for deliberate misinformation." },
  { group: "professional_development", sub: "advocacy", fmt: "scenario", diff: "intermediate", scenario: "A patient's discharge instructions are written at a reading level too high for the patient.", question: "How would you advocate for appropriate health literacy in discharge materials?", answer: "I would supplement the written materials with verbal education using simple language. I would create simplified instructions or use available low-literacy materials. I would use the teach-back method to verify understanding. I would report the health literacy gap to the patient education committee and advocate for materials written at an appropriate reading level. Health literacy barriers contribute to readmissions.", feedback: "Immediate accommodation plus systemic advocacy for appropriate materials." },
  { group: "professional_development", sub: "patient_communication", fmt: "scenario", diff: "beginner", scenario: "A patient who is non-verbal due to intubation is trying to communicate.", question: "How would you help an intubated patient communicate?", answer: "I would provide communication tools: a writing board, alphabet board, picture board, or communication app on a tablet. I would ask yes/no questions that the patient can answer by nodding. I would be patient and give them time to communicate. I would ensure the call bell is within reach and respond promptly. I would assess for pain and other needs through systematic questioning.", feedback: "Multi-modal communication tools for intubated patients." },
  { group: "professional_development", sub: "patient_communication", fmt: "scenario", diff: "intermediate", scenario: "A family member is angry that their loved one was moved to a different room without notification.", question: "How would you address a family communication failure?", answer: "I would apologize for the communication gap: 'I am sorry you were not informed about the room change. I understand how concerning that must have been.' I would explain the reason for the move and show them to the new room. I would document the communication failure and discuss with the team how to improve family notification for future room changes.", feedback: "Sincere apology, explanation, and process improvement." },
];

const cnTemplates: QTemplate[] = [
  { group: "career_navigation", sub: "job_offer_negotiation", fmt: "scenario", diff: "intermediate", scenario: "You want to negotiate for a specific shift differential.", question: "How would you negotiate for better shift differential pay?", answer: "I would research the market rate for shift differentials in my area. I would present my request professionally: 'I noticed that your shift differential for nights is lower than the regional average. Given that I am willing to work nights, I would like to discuss whether there is flexibility in the differential.' I would frame it as a win-win: competitive pay reduces turnover.", feedback: "Market-based negotiation for specific compensation components." },
  { group: "career_navigation", sub: "probation_period", fmt: "scenario", diff: "beginner", scenario: "You are unsure about the expectations during your probation period.", question: "How would you clarify probation expectations?", answer: "I would schedule a meeting with my manager early in probation: 'I want to make sure I am meeting your expectations. Can we review the specific goals and benchmarks for my probation period?' I would take notes, ask for measurable criteria, and schedule regular check-ins to track progress. Proactive clarity-seeking shows initiative and prevents surprises at evaluation time.", feedback: "Proactive expectation clarification prevents evaluation surprises." },
  { group: "career_navigation", sub: "performance_evaluation", fmt: "scenario", diff: "intermediate", scenario: "You want to use your evaluation to advocate for a transfer to another unit.", question: "How would you express a desire to transfer during your evaluation?", answer: "I would frame it positively: 'I have enjoyed my time on this unit and feel I have developed a strong foundation. I am interested in exploring a specialty that aligns with my career goals—specifically [unit]. Can we discuss a timeline and what I would need to accomplish to be considered for a transfer?' I would ensure I have been a strong performer before making the request.", feedback: "Positive framing of transfer requests with career alignment." },
  { group: "career_navigation", sub: "career_advancement", fmt: "scenario", diff: "beginner", scenario: "You want to develop leadership skills but do not have a formal leadership position.", question: "How can you develop leadership without a formal role?", answer: "I would look for informal leadership opportunities: organizing unit events, leading a staff education session, mentoring newer nurses, volunteering for the unit council, or taking charge of a quality improvement project. I would also seek feedback on my leadership potential and find a leadership mentor. Formal titles are not required to demonstrate leadership.", feedback: "Informal leadership development through everyday opportunities." },
  { group: "career_navigation", sub: "career_advancement", fmt: "scenario", diff: "intermediate", scenario: "You are deciding between specializing early or gaining broad experience first.", question: "Should you specialize early or build general experience?", answer: "I would recommend building a solid foundation in a general area first—typically 1-2 years of medical-surgical or similar broad experience. This builds clinical judgment, time management, and assessment skills transferable to any specialty. Early specialization can limit your clinical breadth. However, if you have a strong passion for a specific area that offers new graduate programs, that can also be a valid path.", feedback: "Balanced perspective on specialization timing with individual consideration." },
  { group: "career_navigation", sub: "job_offer_negotiation", fmt: "scenario", diff: "beginner", scenario: "You receive a verbal offer but want to see it in writing before accepting.", question: "How would you request a written offer?", answer: "I would express gratitude and request formalization: 'Thank you so much for this offer—I am very excited about the opportunity. Before I accept, could I receive the offer in writing including the salary, benefits, orientation details, and start date? I want to review everything carefully to make an informed decision.' This is a standard professional request that any reputable employer will accommodate.", feedback: "Written offers protect both parties and are standard practice." },
  { group: "career_navigation", sub: "probation_period", fmt: "scenario", diff: "intermediate", scenario: "Your probation is ending and you want to ensure a smooth transition to regular status.", question: "How would you prepare for the end of your probation?", answer: "I would request a meeting with my manager to review my performance, discuss any remaining concerns, and set goals for the next phase. I would prepare a self-assessment highlighting my growth, competencies achieved, and areas for continued development. I would ensure all orientation checklists are complete and documented. I would express my commitment to the unit and team.", feedback: "Prepared transition with self-assessment and forward-looking goals." },
];

